dSuggestion struct {\r\n\tsuggestion           Suggestion\r\n\trepeatedMentionCount int\r\n}\r\n\r\n// SuggestionsFromEvidence ranks deterministic evidence candidates. Repeated\r\n// evidence is logarithmically capped, and evidence sources with broad fanout\r\n// are discounted so one large commit or directory does not dominate the list.\r\nfunc SuggestionsFromEvidence(document string, candidates []evidence.Candidate) []Suggestion {\r\n\tfanout := make(map[evidenceAtom]int)\r\n\tfor _, candidate := range candidates {\r\n\t\tfor _, item := range candidate.Evidence {\r\n\t\t\tfanout[suggestionEvidenceAtom(item)]++\r\n\t\t}\r\n\t}\r\n\r\n\tranked := make([]rankedSuggestion, 0, len(candidates))\r\n\tfor _, candidate := range candidates {\r\n\t\tif !admitSuggestionCandidate(candidate) {\r\n\t\t\tcontinue\r\n\t\t}\r\n\t\titemResult := rankedSuggestion{\r\n\t\t\tsuggestion: Suggestion{Link: Link{Document: document, Target: candidate.Path}},\r\n\t\t}\r\n\t\tfor _, item := range candidate.Evidence {\r\n\t\t\tatom := suggestionEvidenceAtom(item)\r\n\t\t\toccurrences := item.Count\r\n\t\t\tif occurrences < 1 {\r\n\t\t\t\toccurrences = 1\r\n\t\t\t}\r\n\t\t\toccurrenceFactor := 1 + math.Log2(float64(occurrences))\r\n\t\t\tif item.Kind == evidence.KindExactPathMention || item.Kind == evidence.KindUniqueBasenameMention {\r\n\t\t\t\toccurrenceFactor = 1\r\n\t\t\t}\r\n\t\t\tbreadth := fanout[atom]\r\n\t\t\tif breadth < 1 {\r\n\t\t\t\tbreadth = 1\r\n\t\t\t}\r\n\t\t\titemResult.suggestion.Score += evidenceWeight(item.Kind) *\r\n\t\t\t\toccurrenceFactor /\r\n\t\t\t\tmath.Log2(float64(breadth+1))\r\n\r\n\t\t\tdetail := fmt.Sprintf(\"%s:%s\", item.Kind, item.Detail)\r\n\t\t\tif item.Source != \"\" {\r\n\t\t\t\tdetail = fmt.Sprintf(\"%s:%s:%s\", item.Kind, item.Source, item.Detail)\r\n\t\t\t}\r\n\t\t\tif item.Count > 1 {\r\n\t\t\t\tdetail = fmt.Sprintf(\"%s:x%d\", detail, item.Count)\r\n\t\t\t}\r\n\t\t\titemResult.suggestion.Evidence = append(itemResult.suggestion.Evidence, detail)\r\n\t\t\tif item.Kind == evidence.KindExactPathMention && item.Count >= RepeatedMentionMinimumCount {\r\n\t\t\t\titemResult.repeatedMentionCount = item.Count\r\n\t\t\t}\r\n\t\t}\r\n\t\tsort.Strings(itemResult.suggestion.Evidence)\r\n\t\tranked = append(ranked, itemResult)\r\n\t}\r\n\r\n\treturn selectRankedSuggestions(ranked)\r\n}\r\n\r\nfunc selectRankedSuggestions(ranked []rankedSuggestion) []Suggestion {\r\n\tsort.Slice(ranked, func(i, j int) bool {\r\n\t\tif ranked[i].suggestion.Score != ranked[j].suggestion.Score {\r\n\t\t\treturn ranked[i].suggestion.Score > ranked[j].suggestion.Score\r\n\t\t}\r\n\t\treturn ranked[i].suggestion.Target < ranked[j].suggestion.Target\r\n\t})\r\n\r\n\tselected := make(map[string]rankedSuggestion)\r\n\tlimit := min(DefaultSuggestionLimitPerDocument, len(ranked))\r\n\tfor _, item := range ranked[:limit] {\r\n\t\tselected[item.suggestion.Target] = item\r\n\t}\r\n\r\n\trepeated := append([]rankedSuggestion(nil), ranked...)\r\n\tsort.Slice(repeated, func(i, j int) bool {\r\n\t\tif repeated[i].repeatedMentionCount != repeated[j].repeatedMentionCount {\r\n\t\t\treturn repeated[i].repeatedMentionCount > repeated[j].repeatedMentionCount\r\n\t\t}\r\n\t\tif repeated[i].suggestion.Score != repeated[j].suggestion.Score {\r\n\t\t\treturn repeated[i].suggestion.Score > repeated[j].suggestion.Score\r\n\t\t}\r\n\t\treturn repeated[i].suggestion.Target < repeated[j].suggestion.Target\r\n\t})\r\n\treserved := 0\r\n\tfor _, item := range repeated {\r\n\t\tif item.repeatedMentionCount < RepeatedMentionMinimumCount || reserved >= RepeatedMentionReservePerDocument {\r\n\t\t\tbreak\r\n\t\t}\r\n\t\tif _, exists := selected[item.suggestion.Target]; exists {\r\n\t\t\tcontinue\r\n\t\t}\r\n\t\tselected[item.suggestion.Target] = item\r\n\t\treserved++\r\n\t}\r\n\r\n\tresult := make([]Suggestion, 0, len(selected))\r\n\tfor _, item := range selected {\r\n\t\tresult = append(result, item.suggestion)\r\n\t}\r\n\tsort.Slice(result, func(i, j int) bool {\r\n\t\tif result[i].Score != result[j].Score {\r\n\t\t\treturn result[i].Score > result[j].Score\r\n\t\t}\r\n\t\treturn result[i].Target < result[j].Target\r\n\t})\r\n\treturn result\r\n}\r\n\r\nfunc suggestionEvidenceAtom(item evidence.Evidence) evidenceAtom {\r\n\tsource := item.Source\r\n\tif source == \"\" {\r\n\t\tsource = string(item.Kind)\r\n\t}\r\n\tdetail := \"\"\r\n\tif item.Kind == evidence.KindDependencyNeighbor || item.Kind == evidence.KindDeclaredSymbolMention {\r\n\t\tdetail = item.Detail\r\n\t}\r\n\treturn evidenceAtom{kind: item.Kind, source: source, detail: detail}\r\n}\r\n\r\nfunc admitSuggestionCandidate(candidate evidence.Candidate) bool {\r\n\tkinds := make(map[evidence.Kind]struct{}, len(candidate.Evidence))\r\n\tfor _, item := range candidate.Evidence {\r\n\t\tkinds[item.Kind] = struct{}{}\r\n\t}\r\n\tif len(kinds) >= 2 {\r\n\t\treturn true\r\n\t}\r\n\tfor kind := range kinds {\r\n\t\tswitch kind {\r\n\t\tcase evidence.KindExactPathMention,\r\n\t\t\tevidence.KindUniqueBasenameMention,\r\n\t\t\tevidence.KindDeclaredSymbolMention,\r\n\t\t\tevidence.KindTestCounterpart,\r\n\t\t\tevidence.KindDependencyNeighbor,\r\n\t\t\tevidence.KindRelatedDocumentTarget:\r\n\t\t\treturn true\r\n\t\t}\r\n\t}\r\n\treturn false\r\n}\r\n\r\nfunc evidenceWeight(kind evidence.Kind) float64 {\r\n\tswitch kind {\r\n\tcase evidence.KindExactPathMention:\r\n\t\treturn 6\r\n\tcase evidence.KindUniqueBasenameMention:\r\n\t\treturn 4\r\n\tcase evidence.KindDeclaredSymbolMention:\r\n\t\treturn 7\r\n\tcase evidence.KindTestCounterpart:\r\n\t\treturn 6\r\n\tcase evidence.KindDependencyNeighbor:\r\n\t\treturn 4\r\n\tcase evidence.KindRelatedDocumentTarget:\r\n\t\treturn 4\r\n\tcase evidence.KindSiblingTarget:\r\n\t\treturn 2\r\n\tcase evidence.KindGitTargetCoChange:\r\n\t\treturn 1.5\r\n\tcase evidence.KindGitDocumentCoChange:\r\n\t\treturn 1\r\n\tdefault:\r\n\t\treturn 1\r\n\t}\r\n}\r\npackage codemapcorpus\r\n\r\nimport (\r\n\t\"fmt\"\r\n\t\"os\"\r\n\t\"path/filepath\"\r\n\r\n\t\"github.com/Lokee86/demon-docs/internal/codemap\"\r\n)\r\n\r\nfunc Build(repositoryRoot string, dataset codemap.Dataset, options Options) (Corpus, error) {\r\n\troot, err := filepath.Abs(repositoryRoot)\r\n\tif err != nil {\r\n\t\treturn Corpus{}, err\r\n\t}\r\n\toptions = normalizeOptions(options)\r\n\tfiles, err := repositoryFiles(root)\r\n\tif err != nil {\r\n\t\treturn Corpus{}, err\r\n\t}\r\n\tpaths := repositoryPaths(files)\r\n\tdocuments, err := loadDocuments(root, dataset)\r\n\tif err != nil {\r\n\t\treturn Corpus{}, err\r\n\t}\r\n\ttargets := resolvedTargets(dataset)\r\n\tdependencies, err := collectDependencies(root, files)\r\n\tif err != nil {\r\n\t\treturn Corpus{}, err\r\n\t}\r\n\tsymbols, err := collectSymbolDeclarations(root, files)\r\n\tif err != nil {\r\n\t\treturn Corpus{}, err\r\n\t}\r\n\tcommits, err := collectCommits(root, files, options)\r\n\tif err != nil {\r\n\t\treturn Corpus{}, err\r\n\t}\r\n\treturn Corpus{\r\n\t\tRepositoryRoot:     root,\r\n\t\tRepositoryFiles:    files,\r\n\t\tRepositoryPaths:    paths,\r\n\t\tDocuments:          documents,\r\n\t\tTargetsByDocument:  targets,\r\n\t\tDependencyEdges:    dependencies,\r\n\t\tCommits:            commits,\r\n\t\tRelatedDocuments:   collectRelatedDocuments(documents, targets),\r\n\t\tSymbolDeclarations: symbols,\r\n\t}, nil\r\n}\r\n\r\nfunc loadDocuments(root string, dataset codemap.Dataset) (map[string]string, error) {\r\n\tdocuments := make(map[string]string, len(dataset.Documents))\r\n\tfor _, record := range dataset.Documents {\r\n\t\tdocumentPath := normalizePath(record.Path)\r\n\t\tif documentPath == \"\" {\r\n\t\t\treturn nil, fmt.Errorf(\"invalid document path %q\", record.Path)\r\n\t\t}\r\n\t\tfullPath := filepath.Join(root, filepath.FromSlash(documentPath))\r\n\t\tif !within(root, fullPath) {\r\n\t\t\treturn nil, fmt.Errorf(\"document %s is outside repository\", documentPath)\r\n\t\t}\r\n\t\tcontents, err := os.ReadFile(fullPath)\r\n\t\tif err != nil {\r\n\t\t\treturn nil, fmt.Errorf(\"read document %s: %w\", documentPath, err)\r\n\t\t}\r\n\t\tdocuments[documentPath] = string(contents)\r\n\t}\r\n\treturn documents, nil\r\n}\r\n\r\nfunc resolvedTargets(dataset codemap.Dataset) map[string][]string {\r\n\tsets := map[string]map[string]struct{}{}\r\n\tfor _, item := range dataset.Entries {\r\n\t\tdocument := normalizePath(item.Entry.DocumentPath)\r\n\t\tif document == \"\" {\r\n\t\t\tcontinue\r\n\t\t}\r\n\t\tif sets[document] == nil {\r\n\t\t\tsets[document] = map[string]struct{}{}\r\n\t\t}\r\n\t\tswitch item.Resolution.Status {\r\n\t\tcase codemap.ResolutionResolved, codemap.ResolutionSymbolUnverified, codemap.ResolutionKindMismatch:\r\n\t\t\tif target := normalizePath(item.Resolution.ResolvedPath); target != \"\" {\r\n\t\t\t\tsets[document][target] = struct{}{}\r\n\t\t\t}\r\n\t\tcase codemap.ResolutionPatternResolved:\r\n\t\t\tfor _, match := range item.Resolution.Matches {\r\n\t\t\t\tif target := normalizePath(match.Path); target != \"\" {\r\n\t\t\t\t\tsets[document][target] = struct{}{}\r\n\t\t\t\t}\r\n\t\t\t}\r\n\t\t}\r\n\t}\r\n\tresult := make(map[string][]string, len(sets))\r\n\tfor document, targets := range sets {\r\n\t\tresult[document] = sortedSet(targets)\r\n\t}\r\n\treturn result\r\n}\r\npackage codemapcorpus\r\n\r\nimport (\r\n\t\"fmt\"\r\n\t\"path\"\r\n\t\"sort\"\r\n\t\"strings\"\r\n\r\n\t\"github.com/Lokee86/demon-docs/internal/evidence\"\r\n)\r\n\r\nconst (\r\n\tDefaultMaxCommits        = 1000\r\n\tDefaultMaxPathsPerCommit = 200\r\n)\r\n\r\ntype Options struct {\r\n\tMaxCommits        int\r\n\tMaxPathsPerCommit int\r\n}\r\n\r\ntype Corpus struct {\r\n\tRepositoryRoot     string\r\n\tRepositoryFiles    []string\r\n\tRepositoryPaths    []string\r\n\tDocuments          map[string]string\r\n\tTargetsByDocument  map[string][]string\r\n\tDependencyEdges    []evidence.DependencyEdge\r\n\tCommits            []evidence.Commit\r\n\tRelatedDocuments   map[string][]evidence.RelatedDocument\r\n\tSymbolDeclarations []evidence.SymbolDeclaration\r\n}\r\n\r\nfunc (c Corpus) KnownTargets(documentPath string) []string {\r\n\treturn cloneStrings(c.TargetsByDocument[normalizePath(documentPath)])\r\n}\r\n\r\nfunc (c Corpus) Input(documentPath string, existingTargets []string) (evidence.Input, error) {\r\n\tdocumentPath = normalizePath(documentPath)\r\n\ttext, ok := c.Documents[documentPath]\r\n\tif !ok {\r\n\t\treturn evidence.Input{}, fmt.Errorf(\"document %s is not in the corpus\", documentPath)\r\n\t}\r\n\trepositoryPaths := c.RepositoryPaths\r\n\tif len(repositoryPaths) == 0 {\r\n\t\trepositoryPaths = c.RepositoryFiles\r\n\t}\r\n\treturn evidence.Input{\r\n\t\tDocumentPath:       documentPath,\r\n\t\tDocumentText:       text,\r\n\t\tRepositoryFiles:    repositoryPaths,\r\n\t\tExistingTargets:    cloneStrings(existingTargets),\r\n\t\tDependencyEdges:    c.DependencyEdges,\r\n\t\tCommits:            c.Commits,\r\n\t\tRelatedDocuments:   cloneRelated(c.RelatedDocuments[documentPath]),\r\n\t\tSymbolDeclarations: cloneSymbols(c.SymbolDeclarations),\r\n\t}, nil\r\n}\r\n\r\nfunc normalizeOptions(options Options) Options {\r\n\tif options.MaxCommits <= 0 {\r\n\t\toptions.MaxCommits = DefaultMaxCommits\r\n\t}\r\n\tif options.MaxPathsPerCommit <= 0 {\r\n\t\toptions.MaxPathsPerCommit = DefaultMaxPathsPerCommit\r\n\t}\r\n\treturn options\r\n}\r\n\r\nfunc normalizePath(value string) string {\r\n\tvalue = strings.TrimSpace(strings.ReplaceAll(value, `\\`, \"/\"))\r\n\tvalue = strings.TrimPrefix(value, \"./\")\r\n\tif value == \"\" {\r\n\t\treturn \"\"\r\n\t}\r\n\tclean := path.Clean(value)\r\n\tif clean == \".\" || clean == \"..\" || strings.HasPrefix(clean, \"../\") || strings.HasPrefix(clean, \"/\") {\r\n\t\treturn \"\"\r\n\t}\r\n\treturn clean\r\n}\r\n\r\nfunc sortedSet(values map[string]struct{}) []string {\r\n\tresult := make([]string, 0, len(values))\r\n\tfor value := range values {\r\n\t\tresult = append(result, value)\r\n\t}\r\n\tsort.Strings(result)\r\n\treturn result\r\n}\r\n\r\nfunc cloneStrings(values []string) []string {\r\n\treturn append([]string(nil), values...)\r\n}\r\n\r\nfunc cloneRelated(values []evidence.RelatedDocument) []evidence.RelatedDocument {\r\n\tresult := make([]evidence.RelatedDocument, len(values))\r\n\tfor index, value := range values {\r\n\t\tresult[index] = evidence.RelatedDocument{Path: value.Path, Targets: cloneStrings(value.Targets)}\r\n\t}\r\n\treturn result\r\n}\r\n\r\nfunc cloneSymbols(values []evidence.SymbolDeclaration) []evidence.SymbolDeclaration {\r\n\treturn append([]evidence.SymbolDeclaration(nil), values...)\r\n}\r\n"}],"internal_chat_message_metadata_passthrough":{"turn_id":"019f7aa6-6ccd-7941-8728-30b043aadb30"}}}
