ormat()\r\n\tset := map[string]struct{}{}\r\n\tfor _, item := range dataset.Entries {\r\n\t\tif item.Entry.Heading != \"\" {\r\n\t\t\tset[item.Entry.Heading] = struct{}{}\r\n\t\t}\r\n\t}\r\n\tif len(set) == 0 {\r\n\t\treturn format\r\n\t}\r\n\tformat.SectionHeadings = format.SectionHeadings[:0]\r\n\tfor heading := range set {\r\n\t\tformat.SectionHeadings = append(format.SectionHeadings, heading)\r\n\t}\r\n\tsort.Strings(format.SectionHeadings)\r\n\treturn format\r\n}\r\n\r\nfunc loadBenchmarkLinks(trustedPath string, dataset codemap.Dataset) ([]codemapbench.Link, error) {\r\n\tif trustedPath == \"\" {\r\n\t\treturn codemapbench.ResolvedLinksFromDataset(dataset), nil\r\n\t}\r\n\tfile, err := os.Open(trustedPath)\r\n\tif err != nil {\r\n\t\treturn nil, fmt.Errorf(\"open trusted links: %w\", err)\r\n\t}\r\n\tdefer file.Close()\r\n\tlinks, err := codemapbench.DecodeTrustedReviewLinks(file)\r\n\tif err != nil {\r\n\t\treturn nil, err\r\n\t}\r\n\treturn links, nil\r\n}\r\n\r\nfunc encodeBenchmarkReport(report codemapbench.Report, format string) ([]byte, error) {\r\n\tif format == \"json\" {\r\n\t\treturn codemapbench.MarshalJSONReport(report)\r\n\t}\r\n\treturn []byte(codemapbench.FormatTextReport(report)), nil\r\n}\r\npackage codemapbench\r\n\r\nimport (\r\n\t\"context\"\r\n\t\"errors\"\r\n\t\"fmt\"\r\n\t\"sort\"\r\n)\r\n\r\n// Run hides a deterministic subset of known links, invokes the generator with\r\n// only the remaining links, and classifies every returned suggestion.\r\nfunc Run(ctx context.Context, knownLinks []Link, generator Generator, config Config) (Report, error) {\r\n\tif generator == nil {\r\n\t\treturn Report{}, errors.New(\"benchmark generator is required\")\r\n\t}\r\n\r\n\tvisible, hidden, seed, err := splitHoldout(knownLinks, config)\r\n\tif err != nil {\r\n\t\treturn Report{}, err\r\n\t}\r\n\tknown, _ := normalizeKnownLinks(knownLinks)\r\n\trequest := Request{\r\n\t\tDocuments:    documentPaths(known),\r\n\t\tVisibleLinks: append([]Link(nil), visible...),\r\n\t}\r\n\r\n\traw, err := generator.Generate(ctx, request)\r\n\tif err != nil {\r\n\t\treturn Report{}, fmt.Errorf(\"generate suggestions: %w\", err)\r\n\t}\r\n\r\n\treport := Report{\r\n\t\tSeed:               seed,\r\n\t\tKnownLinks:         known,\r\n\t\tVisibleLinks:       visible,\r\n\t\tHiddenLinks:        hidden,\r\n\t\tRawSuggestionCount: len(raw),\r\n\t}\r\n\tclassifySuggestions(&report, raw)\r\n\tcalculateScores(&report)\r\n\treturn report, nil\r\n}\r\n\r\nfunc classifySuggestions(report *Report, raw []Suggestion) {\r\n\tvisible := linkSet(report.VisibleLinks)\r\n\thidden := linkSet(report.HiddenLinks)\r\n\trecovered := make(map[string]Suggestion, len(report.HiddenLinks))\r\n\tseen := make(map[string]struct{}, len(raw))\r\n\r\n\tfor index, suggestion := range raw {\r\n\t\tnormalized, err := normalizeLink(suggestion.Link)\r\n\t\tif err != nil {\r\n\t\t\treport.InvalidSuggestions = append(report.InvalidSuggestions, InvalidSuggestion{\r\n\t\t\t\tIndex: index, Suggestion: suggestion, Reason: err.Error(),\r\n\t\t\t})\r\n\t\t\tcontinue\r\n\t\t}\r\n\t\tsuggestion.Link = normalized\r\n\t\tkey := linkKey(normalized)\r\n\t\tif _, duplicate := seen[key]; duplicate {\r\n\t\t\treport.DuplicateSuggestions = append(report.DuplicateSuggestions, suggestion)\r\n\t\t\tcontinue\r\n\t\t}\r\n\t\tseen[key] = struct{}{}\r\n\t\treport.UniqueSuggestionCount++\r\n\r\n\t\tif _, ok := hidden[key]; ok {\r\n\t\t\trecovered[key] = suggestion\r\n\t\t\tcontinue\r\n\t\t}\r\n\t\tif _, ok := visible[key]; ok {\r\n\t\t\treport.AlreadyLinked = append(report.AlreadyLinked, suggestion)\r\n\t\t\tcontinue\r\n\t\t}\r\n\t\treport.UnmatchedSuggestions = append(report.UnmatchedSuggestions, suggestion)\r\n\t}\r\n\r\n\tfor _, link := range report.HiddenLinks {\r\n\t\tif suggestion, ok := recovered[linkKey(link)]; ok {\r\n\t\t\treport.RecoveredLinks = append(report.RecoveredLinks, link)\r\n\t\t\treport.RecoveredSuggestions = append(report.RecoveredSuggestions, suggestion)\r\n\t\t\tcontinue\r\n\t\t}\r\n\t\treport.MissedLinks = append(report.MissedLinks, link)\r\n\t}\r\n\tsortSuggestions(report.UnmatchedSuggestions)\r\n\tsortSuggestions(report.AlreadyLinked)\r\n\tsortSuggestions(report.DuplicateSuggestions)\r\n}\r\n\r\nfunc calculateScores(report *Report) {\r\n\tpredicted := len(report.RecoveredLinks) + len(report.UnmatchedSuggestions) + len(report.AlreadyLinked)\r\n\tif predicted > 0 {\r\n\t\treport.Precision = float64(len(report.RecoveredLinks)) / float64(predicted)\r\n\t}\r\n\tif len(report.HiddenLinks) > 0 {\r\n\t\treport.Recall = float64(len(report.RecoveredLinks)) / float64(len(report.HiddenLinks))\r\n\t}\r\n}\r\n\r\nfunc documentPaths(links []Link) []string {\r\n\tset := make(map[string]struct{}, len(links))\r\n\tfor _, link := range links {\r\n\t\tset[link.Document] = struct{}{}\r\n\t}\r\n\tpaths := make([]string, 0, len(set))\r\n\tfor path := range set {\r\n\t\tpaths = append(paths, path)\r\n\t}\r\n\tsort.Strings(paths)\r\n\treturn paths\r\n}\r\n\r\nfunc linkSet(links []Link) map[string]struct{} {\r\n\tset := make(map[string]struct{}, len(links))\r\n\tfor _, link := range links {\r\n\t\tset[linkKey(link)] = struct{}{}\r\n\t}\r\n\treturn set\r\n}\r\npackage codemapbench\r\n\r\nimport (\r\n\t\"fmt\"\r\n\t\"math\"\r\n\t\"sort\"\r\n\r\n\t\"github.com/Lokee86/demon-docs/internal/evidence\"\r\n)\r\n\r\n// DefaultSuggestionLimitPerDocument bounds the ranked list returned per document.\r\n// The benchmark is intended to measure useful surfaced suggestions, not every\r\n// weak relationship that can be inferred from repository history.\r\nconst (\r\n\tDefaultSuggestionLimitPerDocument = 30\r\n\tRepeatedMentionReservePerDocument = 2\r\n\tRepeatedMentionMinimumCount       = 2\r\n)\r\n\r\ntype evidenceAtom struct {\r\n\tkind   evidence.Kind\r\n\tsource string\r\n\tdetail string\r\n}\r\n\r\ntype rankedSuggestion struct {\r\n\tsuggestion           Suggestion\r\n\trepeatedMentionCount int\r\n}\r\n\r\n// SuggestionsFromEvidence ranks deterministic evidence candidates. Repeated\r\n// evidence is logarithmically capped, and evidence sources with broad fanout\r\n// are discounted so one large commit or directory does not dominate the list.\r\nfunc SuggestionsFromEvidence(document string, candidates []evidence.Candidate) []Suggestion {\r\n\tfanout := make(map[evidenceAtom]int)\r\n\tfor _, candidate := range candidates {\r\n\t\tfor _, item := range candidate.Evidence {\r\n\t\t\tfanout[suggestionEvidenceAtom(item)]++\r\n\t\t}\r\n\t}\r\n\r\n\tranked := make([]rankedSuggestion, 0, len(candidates))\r\n\tfor _, candidate := range candidates {\r\n\t\tif !admitSuggestionCandidate(candidate) {\r\n\t\t\tcontinue\r\n\t\t}\r\n\t\titemResult := rankedSuggestion{\r\n\t\t\tsuggestion: Suggestion{Link: Link{Document: document, Target: candidate.Path}},\r\n\t\t}\r\n\t\tfor _, item := range candidate.Evidence {\r\n\t\t\tatom := suggestionEvidenceAtom(item)\r\n\t\t\toccurrences := item.Count\r\n\t\t\tif occurrences < 1 {\r\n\t\t\t\toccurrences = 1\r\n\t\t\t}\r\n\t\t\toccurrenceFactor := 1 + math.Log2(float64(occurrences))\r\n\t\t\tif item.Kind == evidence.KindExactPathMention || item.Kind == evidence.KindUniqueBasenameMention {\r\n\t\t\t\toccurrenceFactor = 1\r\n\t\t\t}\r\n\t\t\tbreadth := fanout[atom]\r\n\t\t\tif breadth < 1 {\r\n\t\t\t\tbreadth = 1\r\n\t\t\t}\r\n\t\t\titemResult.suggestion.Score += evidenceWeight(item.Kind) *\r\n\t\t\t\toccurrenceFactor /\r\n\t\t\t\tmath.Log2(float64(breadth+1))\r\n\r\n\t\t\tdetail := fmt.Sprintf(\"%s:%s\", item.Kind, item.Detail)\r\n\t\t\tif item.Source != \"\" {\r\n\t\t\t\tdetail = fmt.Sprintf(\"%s:%s:%s\", item.Kind, item.Source, item.Detail)\r\n\t\t\t}\r\n\t\t\tif item.Count > 1 {\r\n\t\t\t\tdetail = fmt.Sprintf(\"%s:x%d\", detail, item.Count)\r\n\t\t\t}\r\n\t\t\titemResult.suggestion.Evidence = append(itemResult.suggestion.Evidence, detail)\r\n\t\t\tif item.Kind == evidence.KindExactPathMention && item.Count >= RepeatedMentionMinimumCount {\r\n\t\t\t\titemResult.repeatedMentionCount = item.Count\r\n\t\t\t}\r\n\t\t}\r\n\t\tsort.Strings(itemResult.suggestion.Evidence)\r\n\t\tranked = append(ranked, itemResult)\r\n\t}\r\n\r\n\treturn selectRankedSuggestions(ranked)\r\n}\r\n\r\nfunc selectRankedSuggestions(ranked []rankedSuggestion) []Suggestion {\r\n\tsort.Slice(ranked, func(i, j int) bool {\r\n\t\tif ranked[i].suggestion.Score != ranked[j].suggestion.Score {\r\n\t\t\treturn ranked[i].suggestion.Score > ranked[j].suggestion.Score\r\n\t\t}\r\n\t\treturn ranked[i].suggestion.Target < ranked[j].suggestion.Target\r\n\t})\r\n\r\n\tselected := make(map[string]rankedSuggestion)\r\n\tlimit := min(DefaultSuggestionLimitPerDocument, len(ranked))\r\n\tfor _, item := range ranked[:limit] {\r\n\t\tselected[item.suggestion.Target] = item\r\n\t}\r\n\r\n\trepeated := append([]rankedSuggestion(nil), ranked...)\r\n\tsort.Slice(repeated, func(i, j int) bool {\r\n\t\tif repeated[i].repeatedMentionCount != repeated[j].repeatedMentionCount {\r\n\t\t\treturn repeated[i].repeatedMentionCount > repeated[j].repeatedMentionCount\r\n\t\t}\r\n\t\tif repeated[i].suggestion.Score != repeated[j].suggestion.Score {\r\n\t\t\treturn repeated[i].suggestion.Score > repeated[j].suggestion.Score\r\n\t\t}\r\n\t\treturn repeated[i].suggestion.Target < repeated[j].suggestion.Target\r\n\t})\r\n\treserved := 0\r\n\tfor _, item := range repeated {\r\n\t\tif item.repeatedMentionCount < RepeatedMentionMinimumCount || reserved >= RepeatedMentionReservePerDocument {\r\n\t\t\tbreak\r\n\t\t}\r\n\t\tif _, exists := selected[item.suggestion.Target]; exists {\r\n\t\t\tcontinue\r\n\t\t}\r\n\t\tselected[item.suggestion.Target] = item\r\n\t\treserved++\r\n\t}\r\n\r\n\tresult := make([]Suggestion, 0, len(selected))\r\n\tfor _, item := range selected {\r\n\t\tresult = append(result, item.suggestion)\r\n\t}\r\n\tsort.Slice(result, func(i, j int) bool {\r\n\t\tif result[i].Score != result[j].Score {\r\n\t\t\treturn result[i].Score > result[j].Score\r\n\t\t}\r\n\t\treturn result[i].Target < result[j].Target\r\n\t})\r\n\treturn result\r\n}\r\n\r\nfunc suggestionEvidenceAtom(item evidence.Evidence) evidenceAtom {\r\n\tsource := item.Source\r\n\tif source == \"\" {\r\n\t\tsource = string(item.Kind)\r\n\t}\r\n\tdetail := \"\"\r\n\tif item.Kind == evidence.KindDependencyNeighbor || item.Kind == evidence.KindDeclaredSymbolMention {\r\n\t\tdetail = item.Detail\r\n\t}\r\n\treturn evidenceAtom{kind: item.Kind, source: source, detail: detail}\r\n}\r\n\r\nfunc admitSuggestionCandidate(candidate evidence.Candidate) bool {\r\n\tkinds := make(map[evidence.Kind]struct{}, len(candidate.Evidence))\r\n\tfor _, item := range candidate.Evidence {\r\n\t\tkinds[item.Kind] = struct{}{}\r\n\t}\r\n\tif len(kinds) >= 2 {\r\n\t\treturn true\r\n\t}\r\n\tfor kind := range kinds {\r\n\t\tswitch kind {\r\n\t\tcase evidence.KindExactPathMention,\r\n\t\t\tevidence.KindUniqueBasenameMention,\r\n\t\t\tevidence.KindDeclaredSymbolMention,\r\n\t\t\tevidence.KindTestCounterpart,\r\n\t\t\tevidence.KindDependencyNeighbor,\r\n\t\t\tevidence.KindRelatedDocumentTarget:\r\n\t\t\treturn true\r\n\t\t}\r\n\t}\r\n\treturn false\r\n}\r\n\r\nfunc evidenceWeight(kind evidence.Kind) float64 {\r\n\tswitch kind {\r\n\tcase evidence.KindExactPathMention:\r\n\t\treturn 6\r\n\tcase evidence.KindUniqueBasenameMention:\r\n\t\treturn 4\r\n\tcase evidence.KindDeclaredSymbolMention:\r\n\t\treturn 7\r\n\tcase evidence.KindTestCounterpart:\r\n\t\treturn 6\r\n\tcase evidence.KindDependencyNeighbor:\r\n\t\treturn 4\r\n\tcase evidence.KindRelatedDocumentTarget:\r\n\t\treturn 4\r\n\tcase evidence.KindSiblingTarget:\r\n\t\treturn 2\r\n\tcase evidence.KindGitTargetCoChange:\r\n\t\treturn 1.5\r\n\tcase evidence.KindGitDocumentCoChange:\r\n\t\treturn 1\r\n\tdefault:\r\n\t\treturn 1\r\n\t}\r\n}\r\n# Codemap Ground-Truth Review\r\n\r\nThis directory contains the manually reviewed Space Rocks codemap subset for the missing-link suggestion benchmark.\r\n\r\nThe subset is deliberately conservative:\r\n\r\n- every trusted entry is an existing document-to-code link already