\r\\nimport sys\\r\\nimport tempfile\\r\\nfrom pathlib import Path\\r\\nfrom typing import Any, Iterable\\r\\n\\r\\n\\r\\nBASE_DIR = Path(__file__).resolve().parents[1]\\r\\nDEFAULT_SOURCE = BASE_DIR / \\\"benchmark.json\\\"\\r\\nDEFAULT_CURATION_DIR = BASE_DIR / \\\"curation\\\"\\r\\nDEFAULT_OUTPUT = BASE_DIR / \\\"space-rocks-precision-benchmark.json\\\"\\r\\nSHARD_NAMES = (\\\"shard-a.json\\\", \\\"shard-b.json\\\", \\\"shard-c.json\\\")\\r\\nSHARD_COUNT = 3\\r\\nSHARD_SIZE = 50\\r\\nAUDIT_FIELDS = (\\r\\n    \\\"document_section\\\",\\r\\n    \\\"document_ref\\\",\\r\\n    \\\"document_excerpt\\\",\\r\\n    \\\"target_ref\\\",\\r\\n    \\\"target_excerpt\\\",\\r\\n    \\\"target_sha256\\\",\\r\\n    \\\"target_kind\\\",\\r\\n)\\r\\nCURATION_FIELDS = {\\\"label\\\", \\\"rationale\\\", \\\"audit\\\"}\\r\\n\\r\\n\\r\\nclass BenchmarkError(ValueError):\\r\\n    \\\"\\\"\\\"Raised when a benchmark or curation shard is invalid.\\\"\\\"\\\"\\r\\n\\r\\n\\r\\ndef read_json(path: Path) -> dict[str, Any]:\\r\\n    try:\\r\\n        with path.open(encoding=\\\"utf-8\\\") as stream:\\r\\n            value = json.load(stream)\\r\\n    except (OSError, json.JSONDecodeError) as exc:\\r\\n        raise BenchmarkError(f\\\"cannot read {path}: {exc}\\\") from exc\\r\\n    if not isinstance(value, dict):\\r\\n        raise BenchmarkError(f\\\"{path} must contain a JSON object\\\")\\r\\n    return value\\r\\n\\r\\n\\r\\ndef write_json(path: Path, value: dict[str, Any], *, force: bool = False) -> None:\\r\\n    if path.exists() and not force:\\r\\n        raise BenchmarkError(f\\\"refusing to overwrite existing file: {path} (use --force)\\\")\\r\\n    path.parent.mkdir(parents=True, exist_ok=True)\\r\\n    with path.open(\\\"w\\\", encoding=\\\"utf-8\\\", newline=\\\"\\\\n\\\") as stream:\\r\\n        json.dump(value, stream, indent=2, ensure_ascii=False)\\r\\n        stream.write(\\\"\\\\n\\\")\\r\\n\\r\\n\\r\\ndef pair(record: dict[str, Any]) -> tuple[str, str]:\\r\\n    return (record.get(\\\"document\\\", \\\"<missing document>\\\"), record.get(\\\"target\\\", \\\"<missing target>\\\"))\\r\\n\\r\\n\\r\\ndef canonical_key(record: dict[str, Any]) -> tuple[str, int, str]:\\r\\n    rank = record.get(\\\"rank\\\")\\r\\n    if not isinstance(rank, int) or isinstance(rank, bool):\\r\\n        raise BenchmarkError(f\\\"record {pair(record)!r} has a non-integer rank\\\")\\r\\n    return (record.get(\\\"document\\\", \\\"\\\"), rank, record.get(\\\"target\\\", \\\"\\\"))\\r\\n\\r\\n\\r\\ndef records(value: dict[str, Any], path: Path) -> list[dict[str, Any]]:\\r\\n    suggestions = value.get(\\\"suggestions\\\")\\r\\n    if not isinstance(suggestions, list) or not all(isinstance(item, dict) for item in suggestions):\\r\\n        raise BenchmarkError(f\\\"{path} must contain a suggestions array of objects\\\")\\r\\n    return suggestions\\r\\n\\r\\n\\r\\ndef metadata(value: dict[str, Any], path: Path) -> dict[str, Any]:\\r\\n    required = (\\\"schema_version\\\", \\\"corpus\\\", \\\"sampling\\\")\\r\\n    missing = [field for field in required if field not in value]\\r\\n    if missing:\\r\\n        raise BenchmarkError(f\\\"{path} is missing metadata field(s): {', '.join(missing)}\\\")\\r\\n    return {field: value[field] for field in required}\\r\\n\\r\\n\\r\\ndef validate_source(source: dict[str, Any], path: Path) -> list[dict[str, Any]]:\\r\\n    source_metadata = metadata(source, path)\\r\\n    if not isinstance(source_metadata[\\\"schema_version\\\"], int):\\r\\n        raise BenchmarkError(f\\\"{path} has a non-integer schema_version\\\")\\r\\n    source_records = records(source, path)\\r\\n    if len(source_records) != SHARD_COUNT * SHARD_SIZE:\\r\\n        raise BenchmarkError(\\r\\n            f\\\"{path} has {len(source_records)} suggestions; expected {SHARD_COUNT * SHARD_SIZE}\\\"\\r\\n        )\\r\\n    seen: set[tuple[str, str]] = set()\\r\\n    for record in source_records:\\r\\n        current_pair = pair(record)\\r\\n        if current_pair in seen:\\r\\n            raise BenchmarkError(f\\\"source contains duplicate document/target pair: {current_pair}\\\")\\r\\n        seen.add(current_pair)\\r\\n        if \\\"label\\\" not in record or \\\"audit\\\" not in record:\\r\\n            raise BenchmarkError(f\\\"source record {current_pair} is missing label or audit\\\")\\r\\n        if not isinstance(record[\\\"audit\\\"], dict) or set(record[\\\"audit\\\"]) != set(AUDIT_FIELDS):\\r\\n            raise BenchmarkError(f\\\"source record {current_pair} has an invalid audit shape\\\")\\r\\n    ordered = sorted(source_records, key=canonical_key)\\r\\n    if source_records != ordered:\\r\\n        raise BenchmarkError(f\\\"{path} is not in canonical document/rank/target order\\\")\\r\\n    return source_records\\r\\n\\r\\n\\r\\ndef source_envelope(source: dict[str, Any]) -> dict[str, Any]:\\r\\n    return {\\r\\n        \\\"schema_version\\\": copy.deepcopy(source[\\\"schema_version\\\"]),\\r\\n        \\\"corpus\\\": copy.deepcopy(source[\\\"corpus\\\"]),\\r\\n        \\\"sampling\\\": copy.deepcopy(source[\\\"sampling\\\"]),\\r\\n    }\\r\\n\\r\\n\\r\\ndef split(source_path: Path, curation_dir: Path, *, force: bool = False) -> list[Path]:\\r\\n    source = read_json(source_path)\\r\\n    source_records = validate_source(source, source_path)\\r\\n    output_paths: list[Path] = []\\r\\n    for index, name in enumerate(SHARD_NAMES):\\r\\n        shard_path = curation_dir / name\\r\\n        shard = source_envelope(source)\\r\\n        shard[\\\"suggestions\\\"] = copy.deepcopy(source_records[index * SHARD_SIZE : (index + 1) * SHARD_SIZE])\\r\\n        write_json(shard_path, shard, force=force)\\r\\n        output_paths.append(shard_path)\\r\\n    return output_paths\\r\\n\\r\\n\\r\\ndef validate_shard(\\r\\n    shard: dict[str, Any],\\r\\n    shard_path: Path,\\r\\n    expected_metadata: dict[str, Any],\\r\\n    expected_by_pair: dict[tuple[str, str], dict[str, Any]],\\r\\n) -> list[dict[str, Any]]:\\r\\n    if metadata(shard, shard_path) != expected_metadata:\\r\\n        raise BenchmarkError(f\\\"{shard_path} has wrong corpus/sampling/schema metadata\\\")\\r\\n    shard_records = records(shard, shard_path)\\r\\n    if len(shard_records) != SHARD_SIZE:\\r\\n        raise BenchmarkError(f\\\"{shard_path} has {len(shard_records)} suggestions; expected {SHARD_SIZE}\\\")\\r\\n    for record in shard_records:\\r\\n        current_pair = pair(record)\\r\\n        if current_pair not in expected_by_pair:\\r\\n            raise BenchmarkError(f\\\"{shard_path} contains unknown suggestion pair: {current_pair}\\\")\\r\\n        if \\\"label\\\" not in record or not isinstance(record[\\\"label\\\"], str):\\r\\n            raise BenchmarkError(f\\\"{shard_path} record {current_pair} is missing a string label\\\")\\r\\n        if \\\"audit\\\" not in record or not isinstance(record[\\\"audit\\\"], dict):\\r\\n            raise BenchmarkError(f\\\"{shard_path} record {current_pair} is missing an audit object\\\")\\r\\n        if set(record[\\\"audit\\\"]) != set(AUDIT_FIELDS):\\r\\n            raise BenchmarkError(f\\\"{shard_path} record {current_pair} is missing or has extra audit fields\\\")\\r\\n        if any(not isinstance(record[\\\"audit\\\"][field], str) for field in AUDIT_FIELDS):\\r\\n            raise BenchmarkError(f\\\"{shard_path} record {current_pair} has non-string audit fields\\\")\\r\\n        expected = expected_by_pair[current_pair]\\r\\n        for field, expected_value in expected.items():\\r\\n            if field not in CURATION_FIELDS and record.get(field) != expected_value:\\r\\n                raise BenchmarkError(f\\\"{shard_path} changed immutable field {field!r} for {current_pair}\\\")\\r\\n    return shard_records\\r\\n\\r\\n\\r\\ndef merge(source_path: Path, shard_paths: Iterable[Path], output_path: Path, *, force: bool = False) -> Path:\\r\\n    source = read_json(source_path)\\r\\n    source_records = validate_source(source, source_path)\\r\\n    expected_metadata = metadata(source, source_path)\\r\\n    expected_by_pair = {pair(record): record for record in source_records}\\r\\n    merged: list[dict[str, Any]] = []\\r\\n    seen: set[tuple[str, str]] = set()\\r\\n    paths = list(shard_paths)\\r\\n    if len(paths) != SHARD_COUNT:\\r\\n        raise BenchmarkError(f\\\"expected exactly {SHARD_COUNT} shard files, got {len(paths)}\\\")\\r\\n    for shard_path in paths:\\r\\n        shard_records = validate_shard(read_json(shard_path), shard_path, expected_metadata, expected_by_pair)\\r\\n        for record in shard_records:\\r\\n            current_pair = pair(record)\\r\\n            if current_pair in seen:\\r\\n                raise BenchmarkError(f\\\"duplicate document/target pair across shards: {current_pair}\\\")\\r\\n            seen.add(current_pair)\\r\\n            merged.append(record)\\r\\n    expected_pairs = set(expected_by_pair)\\r\\n    if seen != expected_pairs:\\r\\n        missing = sorted(expected_pairs - seen)\\r\\n        extra = sorted(seen - expected_pairs)\\r\\n        raise BenchmarkError(f\\\"incomplete coverage: missing={missing!r}, extra={extra!r}\\\")\\r\\n    result = source_envelope(source)\\r\\n    result[\\\"suggestions\\\"] = sorted(merged, key=canonical_key)\\r\\n    write_json(output_path, result, force=force)\\r\\n    return output_path\\r\\n\\r\\n\\r\\ndef check(source_path: Path) -> None:\\r\\n    \\\"\\\"\\\"Run split/merge checks, including expected failure cases.\\\"\\\"\\\"\\r\\n    source = read_json(source_path)\\r\\n    source_records = validate_source(source, source_path)\\r\\n    temp_root = BASE_DIR / \\\".pytest_tmp\\\"\\r\\n    temp_root.mkdir(parents=True, exist_ok=True)\\r\\n    with tempfile.TemporaryDirectory(dir=temp_root, prefix=\\\"codemap-precision-\\\") as temp:\\r\\n        temp_dir = Path(temp)\\r\\n        shard_dir = temp_dir / \\\"curation\\\"\\r\\n        paths = split(source_path, shard_dir)\\r\\n        merged_path = temp_dir / \\\"merged.json\\\"\\r\\n        merge(source_path, paths, merged_path)\\r\\n        merged = read_json(merged_path)\\r\\n        if merged[\\\"suggestions\\\"] != source_records:\\r\\n            raise BenchmarkError(\\\"split/merge round trip changed the uncurated records\\\")\\r\\n\\r\\n        def expect_failure(name: str, mutate: Any) -> None:\\r\\n            case_dir = temp_dir / name\\r\\n            case_dir.mkdir()\\r\\n            case_paths = split(source_path, case_dir)\\r\\n            mutate(case_paths)\\r\\n            try:\\r\\n                merge(source_path, case_paths, case_dir / \\\"out.json\\\")\\r\\n            except BenchmarkError:\\r\\n                return\\r\\n            raise BenchmarkError(f\\\"self-check did not reject {name}\\\")\\r\\n\\r\\n        def duplicate(paths: list[Path]) -> None:\\r\\n            value = read_json(paths[1])\\r\\n            value[\\\"suggestions\\\"][0] = read_json(paths[0])[\\\"suggestions\\\"][0]\\r\\n            write_json(paths[1], value, force=True)\\r\\n\\r\\n        def missing_label(paths: list[Path]) -> None:\\r\\n            value = read_json(paths[0])\\r\\n            del value[\\\"suggestions\\\"][0][\\\"label\\\"]\\r\\n            write_json(paths[0], value, force=True)\\r\\n\\r\\n        def wrong_metadata(paths: list[Path]) -> None:\\r\\n            value = read_json(paths[0])\\r\\n            value[\\\"sampling\\\"][\\\"seed\\\"] = \\\"wrong\\\"\\r\\n            write_json(paths[0], value, force=True)\\r\\n\\r\\n        def incomplete(paths: list[Path]) -> None:\\r\\n            value = read_json(paths[2])\\r\\n            value[\\\"suggestions\\\"] = value[\\\"suggestions\\\"][:-1]\\r\\n            write_json(paths[2], value, force=True)\\r\\n\\r\\n        expect_failure(\\\"duplicate\\\", duplicate)\\r\\n        expect_failure(\\\"missing-label\\\", missing_label)\\r\\n        expect_failure(\\\"wrong-metadata\\\", wrong_metadata)\\r\\n        expect_failure(\\\"incomplete\\\", incomplete)\\r\\n\\r\\n\\r\\ndef parser() -> argparse.ArgumentParser:\\r\\n    common = argparse.ArgumentParser(add_help=False)\\r\\n    common.add_argument(\\\"--source\\\", type=Path, default=DEFAULT_SOURCE)\\r\\n    common.add_argument(\\\"--force\\\", action=\\\"store_true\\\", help=\\\"allow overwriting generated files\\\")\\r\\n    command_parser = argparse.ArgumentParser(description=__doc__)\\r\\n    commands = command_parser.add_subparsers(dest=\\\"command\\\", required=True)\\r\\n    split_parser = commands.add_parser(\\\"split\\\", parents=[common], help=\\\"create the three curation shards\\\")\\r\\n    split_parser.add_argument(\\\"--curation-dir\\\", type=Path, default=DEFAULT_CURATION_DIR)\\r\\n    merge_parser = commands.add_parser(\\\"merge\\\", parents=[common], help=\\\"validate and merge three curation shards\\\")\\r\\n    merge_parser.add_argument(\\\"--curation-dir\\\", type=Path, default=DEFAULT_CURATION_DIR)\\r\\n    merge_parser.add_argument(\\\"--output\\\", type=Path, default=DEFAULT_OUTPUT)\\r\\n    merge_parser.add_argument(\\\"--shards\\\", nargs=SHARD_COUNT, type=Path, help=\\\"three shard paths, in any order\\\")\\r\\n    check_parser = commands.add_parser(\\\"check\\\", parents=[common], help=\\\"run split/merge self-checks\\\")\\r\\n    return command_parser\\r\\n\\r\\n\\r\\ndef main(argv: list[str] | None = None) -> int:\\r\\n    args = parser().parse_args(argv)\\r\\n    try:\\r\\n        if args.command == \\\"split\\\":\\r\\n            for path in split(args.source, args.curation_dir, force=args.force):\\r\\n                print(path)\\r\\n        elif args.command == \\\"merge\\\":\\r\\n            shards = args.shards or [args.curation_dir / name for name in SHARD_NAMES]\\r\\n            print(merge(args.source, shards, args.output, force=args.force))\\r\\n        else:\\r\\n            check(args.source)\\r\\n            print(\\\"self-checks passed\\\")\\r\\n    except BenchmarkError as exc:\\r\\n        print(f\\\"error: {exc}\\\", file=sys.stderr)\\r\\n        return 1\\r\\n    return 0\\r\\n\\r\\n\\r\\nif __name__ == \\\"__main__\\\":\\r\\n    raise SystemExit(main())\\r\\n--- merge ---\\r\\n#!/usr/bin/env python3\\r\\n\\\"\\\"\\\"Validate and merge codemap precision curation shards.\\\"\\\"\\\"\\r\\n\\r\\nfrom __future__ import annotations\\r\\n\\r\\nimport argparse\\r\\nimport hashlib\\r\\nimport json\\r\\nfrom pathlib import Path\\r\\nfrom typing import Any\\r\\n\\r\\nLABELS = {\\\"valid_missing_link\\\", \\\"plausible_but_unnecessary\\\", \\\"incorrect\\\"}\\r\\nAUDIT_FIELDS = {\\r\\n    \\\"document_section\\\",\\r\\n    \\\"document_ref\\\",\\r\\n    \\\"document_excerpt\\\",\\r\\n    \\\"target_ref\\\",\\r\\n    \\\"target_excerpt\\\",\\r\\n    \\\"target_sha256\\\",\\r\\n    \\\"target_kind\\\",\\r\\n}\\r\\nMUTABLE_FIELDS = {\\\"label\\\", \\\"rationale\\\", \\\"audit\\\"}\\r\\n\\r\\n\\r\\ndef read(path: Path) -> dict[str, Any]:\\r\\n    with path.open(encoding=\\\"utf-8\\\") as stream:\\r\\n        value = json.load(stream)\\r\\n    if not isinstance(value, dict) or not isinstance(value.get(\\\"suggestions\\\"), list):\\r\\n        raise ValueError(f\\\"invalid benchmark JSON: {path}\\\")\\r\\n    return value\\r\\n\\r\\n\\r\\ndef pair(item: dict[str, Any]) -> tuple[str, str]:\\r\\n    return str(item.get(\\\"document\\\", \\\"\\\")), str(item.get(\\\"target\\\", \\\"\\\"))\\r\\n\\r\\n\\r\\ndef immutable(item: dict[str, Any]) -> dict[str, Any]:\\r\\n    return {key: value for key, value in item.items() if key not in MUTABLE_FIELDS}\\r\\n\\r\\n\\r\\ndef file_hash(path: Path) -> str:\\r\\n    digest = hashlib.sha256()\\r\\n    with path.open(\\\"rb\\\") as stream:\\r\\n        for block in iter(lambda: stream.read(1024 * 1024), b\\\"\\\"):\\r\\n            digest.update(block)\\r\\n    return digest.hexdigest()\\r\\n\\r\\n\\r\\ndef directory_hash(root: Path, directory: Path) -> str:\\r\\n    rows: list[str] = []\\r\\n    for child in sorted(path for path in directory.rglob(\\\"*\\\") if path.is_file()):\\r\\n        rows.append(f\\\"{child.relative_to(root).as_posix()}:{file_hash(child)}\\\")\\r\\n    return hashlib.sha256(\\\"\\\\n\\\".join(rows).encode()).hexdigest()\\r\\n\\r\\n\\r\\ndef verify_target(root: Path, item: dict[str, Any]) -> None:\\r\\n    audit = item[\\\"audit\\\"]\\r\\n    target = root.joinpath(*str(item[\\\"target\\\"]).split(\\\"/\\\"))\\r\\n    kind = audit[\\\"target_kind\\\"]\\r\\n    expected = audit[\\\"target_sha256\\\"]\\r\\n    if target.is_file():\\r\\n        if kind != \\\"file\\\":\\r\\n            raise ValueError(f\\\"{pair(item)} target kind {kind!r}, expected file\\\")\\r\\n        actual = file_hash(target)\\r\\n    elif target.is_dir():\\r\\n        if kind != \\\"directory\\\":\\r\\n            raise ValueError(f\\\"{pair(item)} target kind {kind!r}, expected directory\\\")\\r\\n        actual = directory_hash(root, target)\\r\\n    else:\\r\\n        if kind != \\\"missing\\\":\\r\\n            raise ValueError(f\\\"{pair(item)} target does not exist but kind is {kind!r}\\\")\\r\\n        actual = \\\"\\\"\\r\\n    if expected != actual:\\r\\n        raise ValueError(f\\\"{pair(item)} target SHA mismatch: {expected!r} != {actual!r}\\\")\\r\\n\\r\\n\\r\\ndef merge(source: Path, shards: list[Path], repository: Path, output: Path) -> dict[str, int]:\\r\\n    template = read(source)\\r\\n    envelope = {key: template[key] for key in (\\\"schema_version\\\", \\\"corpus\\\", \\\"sampling\\\")}\\r\\n    expected = {pair(item): item for item in template[\\\"suggestions\\\"]}\\r\\n    if len(expected) != len(template[\\\"suggestions\\\"]):\\r\\n        raise ValueError(\\\"template contains duplicate document-target pairs\\\")\\r\\n\\r\\n    merged: dict[tuple[str, str], dict[str, Any]] = {}\\r\\n    labels = {label: 0 for label in sorted(LABELS)}\\r\\n    for shard_path in shards:\\r\\n        shard = read(shard_path)\\r\\n        if {key: shard[key] for key in envelope} != envelope:\\r\\n            raise ValueError(f\\\"metadata changed in {shard_path}\\\")\\r\\n        for item in shard[\\\"suggestions\\\"]:\\r\\n            key = pair(item)\\r\\n            if key not in expected:\\r\\n                raise ValueError(f\\\"unexpected suggestion in {shard_path}: {key}\\\")\\r\\n            if key in merged:\\r\\n                raise ValueError(f\\\"duplicate curated suggestion: {key}\\\")\\r\\n            if immutable(item) != immutable(expected[key]):\\r\\n                raise ValueError(f\\\"immutable fields changed for {key}\\\")\\r\\n            label = item.get(\\\"label\\\")\\r\\n            if label not in LABELS:\\r\\n                raise ValueError(f\\\"invalid or missing label for {key}: {label!r}\\\")\\r\\n            rationale = str(item.get(\\\"rationale\\\", \\\"\\\")).strip()\\r\\n            if len(rationale) < 20:\\r\\n                raise ValueError(f\\\"rationale too short for {key}\\\")\\r\\n            audit = item.get(\\\"audit\\\")\\r\\n            if not isinstance(audit, dict) or set(audit) != AUDIT_FIELDS:\\r\\n                raise ValueError(f\\\"invalid audit shape for {key}\\\")\\r\\n            for field in AUDIT_FIELDS - {\\\"target_sha256\\\"}:\\r\\n                if not isinstance(audit[field], str) or not audit[field].strip():\\r\\n                    raise ValueError(f\\\"empty audit field {field} for {key}\\\")\\r\\n            verify_target(repository, item)\\r\\n            labels[label] += 1\\r\\n            merged[key] = item\\r\\n\\r\\n    missing = sorted(set(expected) - set(merged))\\r\\n    if missing:\\r\\n        raise ValueError(f\\\"missing {len(missing)} curated suggestions; first: {missing[:3]}\\\")\\r\\n    result = dict(envelope)\\r\\n    result[\\\"suggestions\\\"] = [merged[pair(item)] for item in template[\\\"suggestions\\\"]]\\r\\n    output.parent.mkdir(parents=True, exist_ok=True)\\r\\n    output.write_text(json.dumps(result, indent=2, ensure_ascii=False) + \\\"\\\\n\\\", encoding=\\\"utf-8\\\")\\r\\n    return labels\\r\\n\\r\\n\\r\\ndef main() -> int:\\r\\n    parser = argparse.ArgumentParser(description=__doc__)\\r\\n    parser.add_argument(\\\"--source\\\", type=Path, required=True)\\r\\n    parser.add_argument(\\\"--repository\\\", type=Path, required=True)\\r\\n    parser.add_argument(\\\"--output\\\", type=Path, required=True)\\r\\n    parser.add_argument(\\\"shards\\\", nargs=\\\"+\\\", type=Path)\\r\\n    args = parser.parse_args()\\r\\n    labels = merge(args.source, args.shards, args.repository.resolve(), args.output)\\r\\n    print(json.dumps({\\\"output\\\": str(args.output), \\\"labels\\\": labels}, sort_keys=True))\\r\\n    return 0\\r\\n\\r\\n\\r\\nif __name__ == \\\"__main__\\\":\\r\\n    raise SystemExit(main())\\r\\n--- README relevant ---\\r\\n\\r\\nThis benchmark measures the quality of ordinary missing-link suggestions from the current Demon Docs pipeline. It complements, and does not modify, the positive-only recall benchmark in [`research/codemap-review/space-rocks-trusted-links.json`](../codemap-review/space-rocks-trusted-links.json).\\r\\n\\r\\n## Corpus and sampling\\r\\n\\r\\n- Corpus: Space Rocks revision `3387c94d10fdb94008f27b404098f3e0c32d911c` (10 reviewed documents, 51 trusted links).\\r\\n- Source run: all 51 trusted links were hidden with seed `space-rocks-precision-v1`; the run produced 267 unique suggestions, including 24 recovered trusted links and 243 ordinary unmatched suggestions.\\r\\n- Sample: 150 unique document-target pairs in [`space-rocks-precision-benchmark.json`](space-rocks-precision-benchmark.json).\\r\\n- Sampling: every document’s top five was retained where available; the remainder was selected deterministically with SHA-256 least-represented fill across document area, score bucket, primary evidence kind, and rank bucket.\\r\\n- Labels were assigned after inspecting the referenced document section and target file or directory. Each row records document and target references, excerpts, target kind, a target fingerprint, evidence, and a concise rationale.\\r\\n\\r\\nThe three labels are mutually exclusive: `valid_missing_link` is correct for strict precision, `plausible_but_unnecessary` is accepted only for acceptance precision, and `incorrect` is junk.\\r\\n\\r\\n## Reproduction\\r\\n\\r\\nGenerate the source suggestion report without changing Space Rocks:\\r\\n\\r\\n```text\\r\\ngo run ./cmd/ddocs codemap benchmark --repo D:\\\\!bin\\\\space-rocks --trusted-links research\\\\codemap-review\\\\space-rocks-trusted-links.json --holdout-count 51 --seed space-rocks-precision-v1 --format json --output tmp\\\\codemap-precision\\\\full-hidden.json\\r\\n```\\r\\n\\r\\nEvaluate the labeled sample:\\r\\n\\r\\n```text\\r\\ngo run ./cmd/ddocs codemap precision --benchmark research\\\\codemap-precision\\\\space-rocks-precision-benchmark.json --suggestions tmp\\\\codemap-precision\\\\full-hidden.json\\r\\n```\\r\\n\\r\\nThe evaluator verifies that every sampled pair, score/evidence payload, and rank still exists in the source report before calculating metrics.\\r\\n\\r\\n## Results\\r\\n\\r\\nEvaluation date: 2026-07-19.\\r\\n\\r\\n| metric | result |\\r\\n| --- | ---: |\\r\\n| sample size | 150 |\\r\\n| valid missing link | 98 |\\r\\n| plausible but unnecessary | 26 |\\r\\n| incorrect | 26 |\\r\\n| overall precision | 65.33% |\\r\\n| acceptance precision | 82.67% |\\r\\n| precision@1 | 80.00% |\\r\\n| precision@3 | 73.33% |\\r\\n| precision@5 | 74.00% |\\r\\n\\r\\n### Precision@k by document\\r\\n\\r\\n| document | @1 | @3 | @5 |\\r\\n| --- | ---: | ---: | ---: |\\r\\n| data-sync-and-ssot-pipeline | 0.00% | 0.00% | 0.00% |\\r\\n| observability-contract | 100.00% | 66.67% | 80.00% |\\r\\n| devtools-window | 100.00% | 100.00% | 100.00% |\\r\\n| spawn-tools | 100.00% | 100.00% | 100.00% |\\r\\n| player-data-http-api | 100.00% | 100.00% | 80.00% |\\r\\n| realtime-websocket-protocol | 100.00% | 100.00% | 100.00% |\\r\\n| websocket-connection-lifecycle | 100.00% | 100.00% | 100.00% |\\r\\n| diagnostic-aggregator runtime-and-report-flow | 0.00% | 0.00% | 0.00% |\\r\\n| player-respawn | 100.00% | 66.67% | 80.00% |\\r\\n| profile-stats-flow | 100.00% | 100.00% | 100.00% |\\r\\n\\r\\n### Breakdowns\\r\\n\\r\\n| primary evidence kind | n | valid | accepted | precision | acceptance |\\r\\n| --- | ---: | ---: | ---: | ---: | ---: |\\r\\n| declared_symbol_mention | 58 | 55 | 58 | 94.83% | 100.00% |\\r\\n| exact_path_mention | 52 | 42 | 49 | 80.77% | 94.23% |\\r\\n| unique_basename_mention | 40 | 1 | 17 | 2.50% | 42.50% |\\r\\n\\r\\n| score bucket | n | valid | accepted | precision | acceptance |\\r\\n| --- | ---: | ---: | ---: | ---: | ---: |\\r\\n| `<1` | 13 | 1 | 2 | 7.69% | 15.38% |\\r\\n| `1-<2` | 69 | 35 | 55 | 50.72% | 79.71% |\\r\\n| `2-<8` | 39 | 34 | 38 | 87.18% | 97.44% |\\r\\n| `8+` | 29 | 28 | 29 | 96.55% | 100.00% |\\r\\n\\r\\n| rank bucket | n | valid | accepted | precision | acceptance |\\r\\n| --- | ---: | ---: | ---: | ---: | ---: |\\r\\n| 1-5 | 50 | 37 | 46 | 74.00% | 92.00% |\\r\\n| 6-10 | 33 | 22 | 30 | 66.67% | 90.91% |\\r\\n| 11-20 | 34 | 20 | 26 | 58.82% | 76.47% |\\r\\n| 21+ | 33 | 19 | 22 | 57.58% | 66.67% |\\r\\n\\r\\n### Sampling coverage\\r\\n\\r\\nThe sample covers all 10 documents, all four score buckets, all four rank buckets, all three observed primary evidence kinds, and four document areas: data (26), devtools (41), protocol (33), and services (50). Subsystem counts are recorded in the evaluator’s JSON output and the row-level artifact.\\r\\n\\r\\n## Limitations\\r\\n\\r\\nThis is a curated sample, not an unbiased estimate over every repository path. It is drawn from a full-hidden run of the 51-link trusted corpus, so it evaluates the current evidence pipeline under that benchmark setup and does not measure recall or unseen-document behavior. Directory suggestions are retained as ordinary candidates but are judged conservatively. Labels are auditable and source-pinned, but this artifact has one review pass rather than independent inter